t.script:
const RECORD_ID = ;
const DATA_ROUTE = `/property/land-phase/subproject/data/${RECORD_ID}`;
const SAVE_PHASE_ROUTE = `/property/land-phase/save-phase/subproject/${RECORD_ID}`;
const CLEAR_PHASE_ROUTE = `/property/land-phase/clear-phase/subproject/${RECORD_ID}`;
const SAVE_ROUTE = (lineId) => `/property/unit-map/save/${lineId}`;
const CLEAR_ROUTE = (lineId) => `/property/unit-map/clear/${lineId}`;

const map = L.map('land_phase_map').setView([-18.8792, 47.5079], 16);
L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}', { attribution:'Tiles © Esri', maxZoom:19 }).addTo(map);
const drawnItems = new L.FeatureGroup().addTo(map);
const lockedItems = new L.FeatureGroup().addTo(map);

let units = [];
let unitLayers = [];
let phaseLayer = null;
let activeLayer = null;
let activeEditHandler = null;
const areaInfoBox = document.getElementById('area_info');

const drawControl = new L.Control.Draw({edit:false, draw:{polyline:false, circle:false, circlemarker:false, marker:false, rectangle:true, polygon:{allowIntersection:false, showArea:true}}});
map.addControl(drawControl);

function rpc(route, params) { return fetch(route, {method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({jsonrpc:'2.0', method:'call', params: params || {}})}).then(r => r.json()).then(r => r.result || r); }
function setStatus(msg) { document.getElementById('status_line').innerText = msg || ''; }
function toFeature(geojson) { if (!geojson) return null; if (geojson.type === 'Feature') return geojson; return {type:'Feature', properties:{}, geometry:geojson}; }
function geometryFeature(geometry) { return {type:'Feature', properties:{}, geometry: geometry}; }
function calculateArea(geometry) { try { return Math.round(turf.area(geometryFeature(geometry)) * 100) / 100; } catch(e) { return 0; } }
function formatArea(area) { if (!area) return '0 m²'; if (area >= 10000) return (area / 10000).toFixed(4) + ' ha (' + area.toFixed(2) + ' m²)'; return area.toFixed(2) + ' m²'; }
function unitDisplayLabel(unit) { return unit.label || unit.code || unit.name || 'Lot'; }
function stageLabel(stage) { if (!stage) return stage; const map = { draft: 'Brouillon', sold: 'Vendu', available: 'Disponible', booked: 'Réserv\u00E9', on_lease: 'En location', sale: 'En vente' }; return map[stage] || stage; }
function styleFor(unit) { return {color:unit.color || '#6b7280', fillColor:unit.color || '#6b7280', weight:2, fillOpacity:0.45}; }
function currentPhaseStyle() { return {color:'#dc2626', fillColor:'transparent', weight:4, fillOpacity:0, opacity:1}; }
function lockedPhaseStyle() { return {color:'#6b7280', fillColor:'transparent', weight:2, fillOpacity:0, opacity:0.9, dashArray:'7,6'}; }
function lockedUnitStyle(unit) { return {color:unit.color || '#9ca3af', fillColor:unit.color || '#9ca3af', weight:2, fillOpacity:0.22, opacity:0.85, dashArray:'4,4'}; }
function findUnit(lineId) { return units.find(u => String(u.line_id) === String(lineId)); }
function findLayer(lineId) { return unitLayers.find(l => String((l.meta || {}).line_id) === String(lineId)); }
function popupHtml(unit) { return `<b>${unitDisplayLabel(unit)}</b><br/>Phase : ${unit.phase_name || '-'}<br/>Code : ${unit.code || '-'}<br/>Statut : ${stageLabel(unit.stage) || '-'}<br/>Surface fiche : ${unit.surface || 0}<br/>Prix : ${unit.price || 0}<br/><br/><button type="button" class="btn btn-sm btn-primary js-edit-unit" data-line-id="${unit.line_id}">Modifier dessin</button> <button type="button" class="btn btn-sm btn-success js-save-unit" data-line-id="${unit.line_id}">Enregistrer</button> <button type="button" class="btn btn-sm btn-secondary js-rename-unit" data-line-id="${unit.line_id}">Renommer</button> <button type="button" class="btn btn-sm btn-danger js-clear-unit" data-line-id="${unit.line_id}">Supprimer</button>`; }
function refreshLayerText(layer, unit) { layer.unbindTooltip(); layer.bindTooltip(unitDisplayLabel(unit), {permanent:true, direction:'center', className:'unit-label'}); layer.unbindPopup(); layer.bindPopup(popupHtml(unit)); }
function registerUnitLayer(layer, unit) { layer.meta = unit; layer.setStyle(styleFor(unit)); refreshLayerText(layer, unit); layer.on('click', function() { selectDrawnLot(layer); }); drawnItems.addLayer(layer); unitLayers.push(layer); }
function selectDrawnLot(layer) { if (!layer || !layer.meta) return; activeLayer = layer; document.getElementById('draw_type').value = 'unit'; const select = document.getElementById('unit_select'); if (![...select.options].some(opt => String(opt.value) === String(layer.meta.line_id))) { const opt = document.createElement('option'); opt.value = layer.meta.line_id; opt.textContent = (layer.meta.code ? layer.meta.code + ' - ' : '') + unitDisplayLabel(layer.meta) + ' (dessiné)'; opt.dataset.drawn = '1'; select.appendChild(opt); } select.value = layer.meta.line_id; setStatus('Lot sélectionné : ' + unitDisplayLabel(layer.meta) + '. Vous pouvez modifier, renommer ou supprimer ce dessin.'); }
function renameLot(lineId) { const unit = findUnit(lineId); if (!unit) { alert('Sélectionnez un lot dessiné.'); return; } const label = askUnitLabel(unit); if (!label) return; unit.label = label; const layer = findLayer(lineId); if (layer) { layer.meta = unit; refreshLayerText(layer, unit); saveLayer(layer); } }
function registerCurrentPhase(layer) { if (phaseLayer && drawnItems.hasLayer(phaseLayer)) drawnItems.removeLayer(phaseLayer); phaseLayer = layer; phaseLayer.meta = {type:'phase'}; phaseLayer.setStyle(currentPhaseStyle()); phaseLayer.bindTooltip('', {permanent:true, direction:'center', className:'phase-label'}); drawnItems.addLayer(phaseLayer); }
function registerLockedPhase(phase) { const feature = toFeature(phase.geojson); if (!feature) return; L.geoJSON(feature, {style:lockedPhaseStyle(), interactive:false, onEachFeature:function(f, layer) { layer.bindTooltip(phase.name, {permanent:true, direction:'center', className:'phase-label'}); lockedItems.addLayer(layer); }}); }
function registerLockedUnit(unit) { const feature = toFeature(unit.geojson); if (!feature) return; L.geoJSON(feature, {style:lockedUnitStyle(unit), interactive:false, onEachFeature:function(f, layer) { layer.bindTooltip(unitDisplayLabel(unit), {permanent:true, direction:'center', className:'unit-label'}); lockedItems.addLayer(layer); }}); }
function getRemainingUnits() { return units.filter(u => !u.geojson); }
function getRemainingLotsCount() { return getRemainingUnits().length; }
function updateDivideCountDefault() { const input = document.getElementById('divide_count'); if (!input) return; const remaining = getRemainingLotsCount(); const current = parseInt(input.value || 0); if (!current || current > remaining) input.value = remaining || 1; input.max = remaining || 1; }
function refreshSelect() { const select = document.getElementById('unit_select'); select.innerHTML = '<option value="">Sélectionner un lot...</option>'; getRemainingUnits().forEach(u => { const opt = document.createElement('option'); opt.value = u.line_id; opt.textContent = (u.code ? u.code + ' - ' : '') + unitDisplayLabel(u); select.appendChild(opt); }); updateDivideCountDefault(); }
function askUnitLabel(unit) { const label = prompt("Introduire le label du lot :", unit.label || unit.code || unit.name || ''); if (!label || !label.trim()) { alert('Le label est obligatoire.'); return false; } return label.trim(); }
function updateEditingAreaDisplay(layer) { if (!layer) return; const area = calculateArea(layer.toGeoJSON().geometry); setStatus('Surface dessinée : ' + formatArea(area)); if (areaInfoBox) { areaInfoBox.innerText = 'Surface dessinée : ' + formatArea(area); areaInfoBox.style.display = 'block'; } }
function clearEditingAreaDisplay() { if (areaInfoBox) { areaInfoBox.style.display = 'none'; areaInfoBox.innerText = 'Surface dessinée : 0 m²'; } if (activeLayer && activeEditHandler) activeLayer.off('edit', activeEditHandler); activeEditHandler = null; }
function disableEditing(except) { unitLayers.forEach(l => { if (l !== except && l.editing) l.editing.disable(); }); if (phaseLayer && phaseLayer !== except && phaseLayer.editing) phaseLayer.editing.disable(); clearEditingAreaDisplay(); }
function enablePhaseEdit() { if (!phaseLayer) { setStatus('Aucun dessin de phase. Dessinez la phase active.'); return; } disableEditing(phaseLayer); if (phaseLayer.editing) phaseLayer.editing.enable(); activeLayer = phaseLayer; activeEditHandler = function() { updateEditingAreaDisplay(phaseLayer); }; phaseLayer.on('edit', activeEditHandler); updateEditingAreaDisplay(phaseLayer); }
function enableEdit(lineId) { const layer = findLayer(lineId); if (!layer) { setStatus('Aucun dessin existant pour ce lot. Dessinez un nouveau polygone.'); return; } disableEditing(layer); if (layer.editing) layer.editing.enable(); activeLayer = layer; layer.closePopup(); document.getElementById('unit_select').value = lineId; activeEditHandler = function() { updateEditingAreaDisplay(layer); }; layer.on('edit', activeEditHandler); updateEditingAreaDisplay(layer); }
function savePhaseLayer(layer) { if (!layer) { alert('Dessinez d’abord la phase.'); return; } const geometry = layer.toGeoJSON().geometry; rpc(SAVE_PHASE_ROUTE, {geojson:geometry}).then(res => { if (res.error) { alert(res.error); return; } if (layer.editing) layer.editing.disable(); clearEditingAreaDisplay(); activeLayer = null; document.getElementById('draw_type').value = 'unit'; setStatus('Phase enregistrée.'); }); }
function saveLayer(layer) { if (!layer) return; const unit = layer.meta || findUnit(document.getElementById('unit_select').value); if (!unit) { alert('Sélectionnez un lot.'); return; } if (!unit.label) { const label = askUnitLabel(unit); if (!label) return; unit.label = label; } const geometry = layer.toGeoJSON().geometry; rpc(SAVE_ROUTE(unit.line_id), {geojson:geometry, label:unit.label}).then(res => { if (res.error) { alert(res.error); return; } unit.geojson = geometry; layer.meta = unit; refreshLayerText(layer, unit); if (layer.editing) layer.editing.disable(); clearEditingAreaDisplay(); activeLayer = null; refreshSelect(); setStatus('Lot enregistré : ' + unitDisplayLabel(unit)); }); }
function clearSelected() { if (document.getElementById('draw_type').value === 'phase') { if (!confirm('Supprimer le dessin de la phase active ?')) return; rpc(CLEAR_PHASE_ROUTE, {}).then(() => location.reload()); return; } const lineId = document.getElementById('unit_select').value || (activeLayer && activeLayer.meta ? activeLayer.meta.line_id : false); if (!lineId) { alert('Sélectionnez un lot.'); return; } if (!confirm('Supprimer le dessin de ce lot ?')) return; rpc(CLEAR_ROUTE(lineId), {}).then(() => location.reload()); }
function validateMotherLotDivision() { const checkbox = document.getElementById('divide_mother_lot'); const input = document.getElementById('divide_count'); if (!checkbox || !checkbox.checked) return false; const count = parseInt(input.value || 0); const remaining = getRemainingLotsCount(); if (!count || count < 1) { alert('Veuillez saisir un nombre de lots valide.'); return false; } if (count > remaining) { alert('Impossible de diviser en ' + count + ' lots. Il ne reste que ' + remaining + ' lots disponibles dans cette phase.'); return false; } return true; }
function splitMotherLotGeometry(geometry, count) { const feature = geometryFeature(geometry); const bbox = turf.bbox(feature); const minX = bbox[0], minY = bbox[1], maxX = bbox[2], maxY = bbox[3]; const width = maxX - minX; const height = maxY - minY; const geometries = []; for (let i = 0; i < count; i++) { let clipBox; if (width >= height) { const x1 = minX + (width / count) * i; const x2 = minX + (width / count) * (i + 1); clipBox = [x1, minY, x2, maxY]; } else { const y1 = minY + (height / count) * i; const y2 = minY + (height / count) * (i + 1); clipBox = [minX, y1, maxX, y2]; } const clipped = turf.bboxClip(feature, clipBox); if (clipped && clipped.geometry) geometries.push(clipped.geometry); } return geometries; }
function addGeneratedUnitLayer(unit, geometry) { const feature = toFeature(geometry); if (!feature) return; L.geoJSON(feature, {style:styleFor(unit), onEachFeature:function(f, layer) { registerUnitLayer(layer, unit); }}); }
function saveDividedMotherLot(layer) { if (!validateMotherLotDivision()) return; const count = parseInt(document.getElementById('divide_count').value || 0); const remainingUnits = getRemainingUnits(); const targetUnits = remainingUnits.slice(0, count); const geometries = splitMotherLotGeometry(layer.toGeoJSON().geometry, count); if (geometries.length < count) { alert('La division automatique n’a pas pu générer tous les lots. Essayez un polygone plus simple.'); return; } let chain = Promise.resolve(); targetUnits.forEach((unit, index) => { const geometry = geometries[index]; const label = unit.label || unit.code || unit.name || 'Lot'; chain = chain.then(() => rpc(SAVE_ROUTE(unit.line_id), {geojson:geometry, label:label}).then(res => { if (res.error) throw new Error(res.error); unit.geojson = geometry; unit.label = label; addGeneratedUnitLayer(unit, geometry); })); }); chain.then(() => { refreshSelect(); const remaining = getRemainingLotsCount(); setStatus(count + ' lots créés automatiquement. Il reste ' + remaining + ' lot(s) à dessiner.'); }).catch(err => { alert(err.message || 'Erreur pendant la division automatique.'); }); }

rpc(DATA_ROUTE, {}).then(data => {
    if (data.error) { setStatus(data.error); return; }
    map.setView([data.project.latitude || -18.8792, data.project.longitude || 47.5079], data.project.zoom || 16);
    (data.other_phases || []).forEach(registerLockedPhase);
    (data.other_units || []).forEach(registerLockedUnit);
    const currentFeature = toFeature(data.current_phase ? data.current_phase.geojson : null);
    if (currentFeature) L.geoJSON(currentFeature, {style:currentPhaseStyle(), onEachFeature:function(f, layer) { registerCurrentPhase(layer); }});
    units = data.units || [];
    refreshSelect();
    units.forEach(u => { const feature = toFeature(u.geojson); if (!feature) return; L.geoJSON(feature, {style:styleFor(u), onEachFeature:function(f, layer) { registerUnitLayer(layer, u); }}); });
    const all = new L.FeatureGroup([...drawnItems.getLayers(), ...lockedItems.getLayers()]);
    if (all.getLayers().length) map.fitBounds(all.getBounds(), {padding:[20,20]});
    document.getElementById('draw_type').value = phaseLayer ? 'unit' : 'phase';
});

document.getElementById('btn_search_place').addEventListener('click', function() { const q = document.getElementById('search_place').value; if (!q) { alert('Veuillez saisir un lieu ou des coordonnées.'); return; } const coords = q.split(',').map(x => parseFloat(x.trim())); if (coords.length === 2 && !isNaN(coords[0]) && !isNaN(coords[1])) { map.setView([coords[0], coords[1]], 18); return; } fetch(`https://nominatim.openstreetmap.org/search?format=json&limit=1&q=${encodeURIComponent(q)}`).then(r => r.json()).then(results => { if (!results.length) { alert('Terrain introuvable.'); return; } map.setView([parseFloat(results[0].lat), parseFloat(results[0].lon)], 18); }); });
document.getElementById('btn_use_position').addEventListener('click', function() { if (!navigator.geolocation) { alert('Géolocalisation non supportée par ce navigateur.'); return; } navigator.geolocation.getCurrentPosition(function(pos) { map.setView([pos.coords.latitude, pos.coords.longitude], 18); }); });
map.on(L.Draw.Event.CREATED, function(event) { const drawType = document.getElementById('draw_type').value; if (drawType === 'phase') { if (phaseLayer) { alert('Cette phase est déjà dessinée. Utilisez “Modifier dessin” pour la modifier.'); return; } registerCurrentPhase(event.layer); savePhaseLayer(event.layer); return; } const divideCheckbox = document.getElementById('divide_mother_lot'); if (divideCheckbox && divideCheckbox.checked) { saveDividedMotherLot(event.layer); return; } const lineId = document.getElementById('unit_select').value; if (!lineId) { alert('Sélectionnez d’abord un lot.'); return; } const unit = findUnit(lineId); if (!unit) return; const label = unit.label || askUnitLabel(unit); if (!label) return; unit.label = label; const old = findLayer(lineId); if (old) drawnItems.removeLayer(old); unitLayers = unitLayers.filter(l => String((l.meta || {}).line_id) !== String(lineId)); registerUnitLayer(event.layer, unit); saveLayer(event.layer); });
document.getElementById('btn_rename_selected').addEventListener('click', () => renameLot(document.getElementById('unit_select').value || (activeLayer && activeLayer.meta ? activeLayer.meta.line_id : false)));
document.getElementById('btn_clear_selected').addEventListener('click', clearSelected);
document.addEventListener('click', function(ev) { const edit = ev.target.closest('.js-edit-unit'); const save = ev.target.closest('.js-save-unit'); const rename = ev.target.closest('.js-rename-unit'); const clear = ev.target.closest('.js-clear-unit'); if (edit) enableEdit(edit.dataset.lineId); if (save) saveLayer(findLayer(save.dataset.lineId)); if (rename) renameLot(rename.dataset.lineId); if (clear) { const layer = findLayer(clear.dataset.lineId); if (layer) selectDrawnLot(layer); clearSelected(); } });
document.getElementById('divide_mother_lot').addEventListener('change', updateDivideCountDefault);
document.getElementById('divide_count').addEventListener('change', function() { const remaining = getRemainingLotsCount(); const value = parseInt(this.value || 0); if (value > remaining) { alert('Le nombre demandé dépasse les lots disponibles. Il reste ' + remaining + ' lot(s).'); this.value = remaining || 1; } });

const DATA_ROUTE = `/property/land-phase/project/data/`;
const map = L.map('land_phase_global_map').setView([-18.8792, 47.5079], 16);
L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}', { attribution:'Tiles © Esri', maxZoom:19 }).addTo(map);
const all = new L.FeatureGroup().addTo(map);
function rpc(route, params) { return fetch(route, {method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({jsonrpc:'2.0', method:'call', params: params || {}})}).then(r => r.json()).then(r => r.result || r); }
function toFeature(geojson) { if (!geojson) return null; if (geojson.type === 'Feature') return geojson; return {type:'Feature', properties:{}, geometry:geojson}; }
function unitDisplayLabel(unit) { return unit.label || unit.code || unit.name || 'Lot'; }
function stageLabel(stage) { if (!stage) return stage; const labels = { draft: 'Brouillon', sold: 'Vendu', available: 'Disponible', booked: 'Réserv\u00E9', on_lease: 'En location', sale: 'En vente' }; return labels[stage] || stage; }
function formatNumber(value) { const number = Number(value || 0); return Number.isFinite(number) ? number.toLocaleString('fr-FR') : '0'; }
function formatSurface(value) { return formatNumber(value) + ' m²'; }
function phaseStyle() { return {color:'#6b7280', fillColor:'transparent', weight:3, fillOpacity:0, opacity:0.95, dashArray:'7,6'}; }
function unitStyle(u) { return {color:u.color || '#6b7280', fillColor:u.color || '#6b7280', weight:2, fillOpacity:0.45}; }
rpc(DATA_ROUTE, {exclude_draft: true}).then(data => { map.setView([data.project.latitude || -18.8792, data.project.longitude || 47.5079], data.project.zoom || 16); (data.other_phases || []).forEach(p => { const f = toFeature(p.geojson); if (!f) return; L.geoJSON(f, {style:phaseStyle(), onEachFeature:function(ff, layer) { layer.bindTooltip(p.name, {permanent:true, direction:'center', className:'phase-label'}); all.addLayer(layer); }}); }); (data.units || []).forEach(u => { const f = toFeature(u.geojson); if (!f) return; L.geoJSON(f, {style:unitStyle(u), onEachFeature:function(ff, layer) { layer.bindPopup(`<b>${unitDisplayLabel(u)}</b><br/>Phase : ${u.phase_name || '-'}<br/>Statut : ${stageLabel(u.stage) || '-'}<br/>Surface totale : ${formatSurface(u.surface)}<br/>Prix par m² : ${formatNumber(u.price_per_area)} Ariary/m²<br/>Prix : ${formatNumber(u.price)} Ariary`); layer.bindTooltip(unitDisplayLabel(u), {permanent:true, direction:'center', className:'unit-label'}); layer.on('mouseover', function() { layer.openPopup(); }); layer.on('mouseout', function() { layer.closePopup(); }); layer.on('click', function() { if (u.brocher_access_token) window.location.href = '/property-brochure/' + u.brocher_access_token; }); all.addLayer(layer); }}); }); if (all.getLayers().length) map.fitBounds(all.getBounds(), {padding:[20,20]}); });

body.script:
const DATA_ROUTE = '';
const map = L.map('land_phase_preview_map').setView([-18.8792, 47.5079], 16);
L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}', { attribution:'Tiles © Esri', maxZoom:19 }).addTo(map);
const all = new L.FeatureGroup().addTo(map);
function rpc(route, params) { return fetch(route, {method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({jsonrpc:'2.0', method:'call', params: params || {}})}).then(r => r.json()).then(r => r.result || r); }
function toFeature(geojson) { if (!geojson) return null; if (geojson.type === 'Feature') return geojson; return {type:'Feature', properties:{}, geometry:geojson}; }
function unitDisplayLabel(unit) { return unit.label || unit.code || unit.name || 'Lot'; }
function phaseStyle(active) { return {color: active ? '#dc2626' : '#6b7280', fillColor:'transparent', weight: active ? 4 : 2, fillOpacity:0, opacity:0.95, dashArray: active ? null : '7,6'}; }
function unitStyle(u) { return {color:u.color || '#6b7280', fillColor:u.color || '#6b7280', weight:2, fillOpacity:0.45}; }
rpc(DATA_ROUTE, {}).then(data => { map.setView([data.project.latitude || -18.8792, data.project.longitude || 47.5079], data.project.zoom || 16); if (data.current_phase) { const f = toFeature(data.current_phase.geojson); if (f) L.geoJSON(f, {style:phaseStyle(true), onEachFeature:function(ff, layer) { layer.bindTooltip(data.current_phase.name, {permanent:true, direction:'center', className:'phase-label'}); all.addLayer(layer); }}); } (data.other_phases || []).forEach(p => { const f = toFeature(p.geojson); if (!f) return; L.geoJSON(f, {style:phaseStyle(false), onEachFeature:function(ff, layer) { layer.bindTooltip(p.name, {permanent:true, direction:'center', className:'phase-label'}); all.addLayer(layer); }}); }); (data.other_units || []).forEach(u => { const f = toFeature(u.geojson); if (!f) return; L.geoJSON(f, {style:unitStyle(u), interactive:false, onEachFeature:function(ff, layer) { layer.bindTooltip(unitDisplayLabel(u), {permanent:true, direction:'center', className:'unit-label'}); all.addLayer(layer); }}); }); (data.units || []).forEach(u => { const f = toFeature(u.geojson); if (!f) return; L.geoJSON(f, {style:unitStyle(u), onEachFeature:function(ff, layer) { layer.bindTooltip(unitDisplayLabel(u), {permanent:true, direction:'center', className:'unit-label'}); all.addLayer(layer); }}); }); if (all.getLayers().length) map.fitBounds(all.getBounds(), {padding:[20,20]}); });
